255→const useEmojiImage = (emoji, resolution = 128) => {
256→    const [image, setImage] = useState(() => emojiCanvasCache.get(`${emoji}-${resolution}`) || null);
257→
258→    useEffect(() => {
259→        if(!emoji){
260→            setImage(null);
261→            return;
262→        }
263→
264→        const cacheKey = `${emoji}-${resolution}`;
265→        const cached = emojiCanvasCache.get(cacheKey);
266→        if(cached){
267→            setImage(cached);
268→            return;
269→        }
270→
271→        const canvas = document.createElement("canvas");
272→        canvas.width = resolution;
273→        canvas.height = resolution;
274→        const ctx = canvas.getContext("2d");
275→        ctx.clearRect(0, 0, resolution, resolution);
276→        ctx.textAlign = "center";
277→        ctx.textBaseline = "middle";
278→        ctx.font = `${Math.round(resolution * 0.78)}px "Segoe UI Emoji", "Apple Color Emoji", "Noto Color Emoji", sans-serif`;
279→        ctx.fillText(emoji, resolution / 2, resolution / 2);
280→
281→        const img = new window.Image();
282→        img.onload = () => {
283→            emojiCanvasCache.set(cacheKey, img);
284→            setImage(img);
285→        };
286→        img.src = canvas.toDataURL();
287→    }, [emoji, resolution]);
288→
289→    return image;
290→};
