545→const PuffEffect = ({x, y, id, onComplete}) => {
546→    const [progress, setProgress] = useState(0);
547→    const startRef = useRef(null);
548→    const particlesRef = useRef(null);
549→
550→    if(!particlesRef.current){
551→        const innerCount = 8 + Math.floor(Math.random() * 3);
552→        const outerCount = 5 + Math.floor(Math.random() * 3);
553→        const inner = Array.from({length: innerCount}, () => ({
554→            angle: Math.random() * Math.PI * 2,
555→            distance: 30 + Math.random() * 20,
556→            color: Math.random() > 0.5 ? "#a21caf" : "#e879f9",
557→            ring: 1
558→        }));
559→        const outer = Array.from({length: outerCount}, () => ({
560→            angle: Math.random() * Math.PI * 2,
561→            distance: 50 + Math.random() * 25,
562→            color: Math.random() > 0.5 ? "#f5e6a3" : "#f5c896",
563→            ring: 2
564→        }));
565→        particlesRef.current = [...inner, ...outer];
566→    }
567→
568→    useEffect(() => {
569→        const duration = 600;
570→        let animId;
571→
572→        const animate = (timestamp) => {
573→            if(!startRef.current) startRef.current = timestamp;
574→            const elapsed = timestamp - startRef.current;
575→            const p = Math.min(elapsed / duration, 1);
576→            setProgress(p);
577→
578→            if(p < 1){
579→                animId = requestAnimationFrame(animate);
580→            } else {
581→                onComplete(id);
582→            }
583→        };
584→
585→        animId = requestAnimationFrame(animate);
586→        return () => cancelAnimationFrame(animId);
587→    }, [id, onComplete]);
588→
589→    const particles = particlesRef.current;
590→    const eased = 1 - Math.pow(1 - progress, 2);
591→
592→    return (
593→        <Group x={x} y={y} listening={false}>
594→            <Circle
595→                radius={eased * 28}
596→                stroke="#e879f9"
597→                strokeWidth={Math.max(0.5, 2 * (1 - progress))}
598→                opacity={1 - progress}
599→            />
600→            <Circle
601→                radius={eased * 42}
602→                stroke="#f5e6a3"
603→                strokeWidth={Math.max(0.3, 1.2 * (1 - progress))}
604→                opacity={(1 - progress) * 0.5}
605→            />
606→            {particles.map((p, i) => (
607→                <Circle
608→                    key={i}
609→                    x={Math.cos(p.angle) * p.distance * eased}
610→                    y={Math.sin(p.angle) * p.distance * eased}
611→                    radius={Math.max(0.5, (p.ring === 1 ? 3.5 : 2.5) * (1 - progress))}
612→                    fill={p.color}
613→                    opacity={1 - progress}
614→                />
615→            ))}
616→        </Group>
617→    );
618→};
