    background: rgba(0, 0, 0, 0.2);
}

.fw-draft-note-row input[type="range"]{
    width: 80px;
}

.fw-draft-note-actions{
    display: flex;
    gap: 0.5rem;
}

.fw-draft-note-actions .fw-apply-btn:disabled{
    opacity: 0.35;
    cursor: not-allowed;
}

.freedom-wall-error-toast{
    padding: 0.45rem 0.75rem;
    border-radius: 10px;
    background: rgba(242, 167, 179, 0.12);
    border: 1px solid rgba(242, 167, 179, 0.3);
    color: var(--fw-chalk-pink);
    font-size: 0.74rem;
    font-weight: 600;
}

.fw-modal-backdrop{
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.46);
    backdrop-filter: blur(2px);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 60;
    padding: 1rem;
    box-sizing: border-box;
}

.fw-modal-card{
    width: min(420px, 100%);
    border: 1px solid rgba(220, 225, 220, 0.18);
    background: rgba(24, 22, 20, 0.95);
    border-radius: 14px;
