}

.fw-modal-actions{
    display: flex;
    gap: 0.5rem;
    justify-content: flex-end;
    flex-wrap: wrap;
}

.freedom-wall-footer{
    display: flex;
    justify-content: space-between;
    align-items: center;
    color: var(--fw-chalk-faint);
