}

.fw-zoom-controls button{
    width: 26px;
    height: 26px;
    border: 1px solid rgba(220, 225, 220, 0.12);
    background: rgba(255, 255, 255, 0.06);
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.82rem;
    color: var(--fw-chalk-dim);
    font-weight: 700;
    transition: background 0.15s, color 0.15s;
}

.fw-zoom-controls button:hover{
    background: rgba(255, 255, 255, 0.12);
    color: var(--fw-chalk);
}

.fw-zoom-level{
    min-width: 36px;
    text-align: center;
    color: var(--fw-chalk-faint);
    font-weight: 600;
    font-variant-numeric: tabular-nums;
}

.fw-reset-zoom-btn{
    position: absolute;
    bottom: 10px;
    left: 50%;
    transform: translateX(-50%);
    z-index: 5;
    background: rgba(0, 0, 0, 0.35);
    backdrop-filter: blur(4px);
    border: 1px solid rgba(220, 225, 220, 0.15);
    border-radius: 8px;
    padding: 0.3rem 0.7rem;
    font-size: 0.7rem;
    font-weight: 600;
    color: var(--fw-chalk-dim);
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
}

.fw-reset-zoom-btn:hover{
    background: rgba(0, 0, 0, 0.5);
    color: var(--fw-chalk);
}

.fw-minimap{
    position: absolute;
    bottom: 10px;
    left: 10px;
    width: 100px;
    background: rgba(0, 0, 0, 0.25);
    border: 1px solid rgba(220, 225, 220, 0.1);
    border-radius: 6px;
    overflow: hidden;
    cursor: pointer;
    z-index: 5;
    touch-action: none;
    user-select: none;
}

.fw-minimap-viewport{
    position: absolute;
    left: 0;
    top: 0;
    border: 2px solid var(--fw-chalk-yellow);
