560→            angle: Math.random() * Math.PI * 2,
561→            distance: 50 + Math.random() * 25,
562→            color: Math.random() > 0.5 ? "#f5e6a3" : "#f5c896",
563→            ring: 2
564→        }));
565→        particlesRef.current = [...inner, ...outer];
566→    }
567→
568→    useEffect(() => {
569→        const duration = 600;
570→        let animId;
571→
572→        const animate = (timestamp) => {
573→            if(!startRef.current) startRef.current = timestamp;
574→            const elapsed = timestamp - startRef.current;
575→            const p = Math.min(elapsed / duration, 1);
576→            setProgress(p);
577→
578→            if(p < 1){
579→                animId = requestAnimationFrame(animate);
580→            } else {
581→                onComplete(id);
582→            }
583→        };
584→
585→        animId = requestAnimationFrame(animate);
586→        return () => cancelAnimationFrame(animId);
587→    }, [id, onComplete]);
588→
589→    const particles = particlesRef.current;
590→    const eased = 1 - Math.pow(1 - progress, 2);
591→
592→    return (
593→        <Group x={x} y={y} listening={false}>
594→            <Circle
595→                radius={eased * 28}
596→                stroke="#e879f9"
597→                strokeWidth={Math.max(0.5, 2 * (1 - progress))}
598→                opacity={1 - progress}
